import { NextRequest } from "next/server";
import { cloudinary } from "@workspace/backend/modules/cloudinary/cloudinary.client";

type Variant = "thumb" | "large" | "original";

function getTransformation(variant: Variant): string {
  switch (variant) {
    case "thumb":
      return "w_128,h_128,c_fit,f_auto,q_auto";
    case "large":
      return "w_1024,h_1024,c_fit,f_auto,q_auto";
    case "original":
    default:
      return "f_auto,q_auto";
  }
}

function isValidVariant(value: string | null): value is Variant {
  return value === "thumb" || value === "large" || value === "original";
}

export async function GET(
  req: NextRequest,
  context: { params: Promise<{ publicId: string[] }> }
): Promise<Response> {
  const { params } = context;
  const { publicId } = await params

  if (!publicId || publicId.length === 0) {
    return new Response("Missing publicId", { status: 400 });
  }

  // catch-all -> on reconstruit l'id Cloudinary
  const id = publicId.join("/");

  // exemple usage ensuite
  // const asset = await fetchAuthenticatedAsset(id);
  if (!id) {
    return new Response("Invalid publicId", { status: 400 });
  }

  return new Response(JSON.stringify({ id }), {
    status: 200,
    headers: { "Content-Type": "application/json" },
  });
}